VALUES
  ('disabled-57f41407-moex-00366', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲為受輔助宣告之人，乙為其輔助人，甲欲進行民事訴訟。下列敘述何者 正確？', '["乙同意甲為訴訟行為，應以文書為之", "甲就他造之起訴或上訴為訴訟行為時，無須經乙同意", "甲為捨棄、認諾，應經乙於言詞辯論時同意", "甲為撤回或和解，應經乙以經公證之書面特別同意"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00367', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者不是第三審程序之特別規定？', '["僅得以違背法令為上訴理由", "強制提出上訴理由書", "原則上須以原判決所確定之事實為判決之基礎", "得撤回上訴"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00368', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於第二審訴訟程序，下列敘述何者正確？', '["對於財產權訴訟之第一審判決提起上訴，第二審法院應於上訴聲明之範 圍內為判決", "對於第一審判決提起上訴，上訴人得依訴訟救助之規定，聲請第一審法 院為之選任律師為訴訟代理人", "當事人提起第二審上訴，未於上訴狀內表明上訴理由者，第二審法院應 定相當期間命上訴人提出理由書", "第二審法院不得依職權調查證據"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00369', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲起訴請求乙及丙各應返還借款新臺幣（下同）200 萬元，第一審法院為 甲全部勝訴之判決。乙及丙全部聲明不服，均提起上訴。經第二審法院以 乙已經清償甲 80 萬元，丙對甲另有債權 100 萬元得予抵銷為由，廢棄第 一審判決關於命乙給付甲 80 萬元、丙給付甲 100 萬元部分，並駁回甲此 部分第一審請求，另駁回乙及丙其餘上訴。下列敘述何者正確？', '["甲請求乙及丙返還借款各被駁回80萬元、100萬元，各未逾第三審上訴 利益之數額，因此甲不得提起第三審上訴", "乙之第三審上訴利益為120萬元，已逾100萬元，因此乙得提起第三審 上訴", "丙雖因抵銷抗辯有理由，但仍得就全部敗訴部分提起第三審上訴", "乙、丙均不服第二審判決共同提起上訴，應分別計算乙、丙之第三審上 訴利益"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00370', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於提起再審之訴應具備之程式，下列敘述何者錯誤？', '["再審訴狀應記載當事人之法定代理人，係指於提起再審之訴時有代理權 者而言", "再審訴狀應記載聲明不服之判決，並應添具該確定終局判決之繕本或影 本，否則，其起訴為不合法", "再審訴狀應記載應於如何程度廢棄原判決及就本案如何判決之聲明", "再審訴狀應表明之再審理由，必須指明確定判決有如何合於法定再審事 由之具體情事，如未表明，法院毋庸命補正"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00371', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '下列何者，得提起第三人撤銷訴訟？', '["代位訴訟之被代位債務人，非該訴訟之當事人或參加人，亦未受訴訟告 知者", "前訴訟之當事人於判決確定後死亡，該當事人之繼承人", "於前訴訟之第三審程序始參加訴訟之參加人", "受訴訟告知而未參加訴訟之受告知人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00372', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '債務人對於支付命令，於法定期間異議後撤回其異議，下列敘述何者正確？', '["得隨時撤回異議，且無須負擔訴訟費用", "得隨時撤回異議，但應負擔訴訟費用", "得於第一審言詞辯論終結前撤回異議，但應負擔訴訟費用", "得於第二審言詞辯論終結前撤回異議，但應負擔訴訟費用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00373', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '關於一般公示催告程序，下列敘述何者錯誤？', '["申報權利之公示催告，以得依背書轉讓之證券或法律有規定者為限", "申報權利之期間，除法律別有規定外，自公示催告之公告開始公告於法 院網站之日起、最後登載公報、新聞紙之日起，應有1個月以上", "申報權利在期間已滿後，而在未為除權判決前者，與在期間內申報者， 有同一之效力", "法院就除權判決之聲請為裁判前，得依職權為必要之調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00374', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲、乙、丙繼承其父丁之遺產，甲列乙、丙為被告，訴請法院判決分割遺 產，下列敘述何者正確？', '["甲所為關於遺產分割方法之聲明，法院應受其拘束", "若甲向丁住所地之法院起訴，受訴法院應以裁定移送至丁之主要遺產所 在地法院", "若甲為捨棄，法院不得本於其捨棄而為甲敗訴之判決", "若被告就甲主張之主要事實為訴訟上自認，法院應以該自認之事實作為 裁判之基礎"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00375', 'disabled-57f41407', 'disabled-57f41407-moex-112-1611a566', 'sub-disabled-57f41407-02', NULL, 'single_choice', '甲列乙為被告，請求法院撤銷甲、乙之婚姻並合併請求酌定未成年子女A 由甲任親權人時，下列敘述何者錯誤？', '["法院就酌定親權部分為審理時，應依職權調查證據", "法院就此二事件合併裁判時，應以判決為之", "法院就此二事件為甲全部有理由之裁判，乙就全部終局裁判聲明不服 時，應適用上訴程序", "法院就此二事件為甲全部有理由之裁判，乙僅就酌定親權部分聲明不服 時，應適用上訴程序 乙、刑事訴訟法部分"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:36+00:00", "source_pdf_sha1": "1de48eae2baf", "answer_pdf_sha1": "b2f2ec6bc560", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "506", "s": "0410", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民事訴訟法大意與刑事訴訟法大意", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
